    let mut position = (use_signal(|| props.x), use_signal(|| props.y));
    let mut isDragged = use_signal(|| false);

    let point = rsx! {
        circle {
            class: &quot;point&quot;,
            cx: position.0,
            cy: position.1,
            r: 5, //point radius

            onmousedown:move |_| isDragged.set(true),
            onmouseup:move |_| isDragged.set(false),
            onmousemove:move |e|{
                    if *isDragged.read() {
                        e.stop_propagation();
                        e.prevent_default();
                        let coords = e.element_coordinates();
                        position.0.set(coords.x as usize);
                        position.1.set(coords.y as usize);
                    }
            },
        }
    }
}
</code></pre>
<p>Wishfull implementations :</p>
